import React from 'react';
import { BrowserRouter, Routes, Route } from 'react-router-dom';
import Navbar from './components/Navbar';
import Home from './pages/Home';
import Books from './pages/Books';
import Cart from './pages/Cart';
import Orders from './pages/Orders';

export default function App() {
  return (
    <BrowserRouter>
      <Navbar />
      <Routes>
        <Route path='/' element={<Home />} />
        <Route path='/books' element={<Books />} />
        <Route path='/cart' element={<Cart />} />
        <Route path='/orders' element={<Orders />} />
      </Routes>
    </BrowserRouter>
  );
}

import React from 'react';
import { NavLink } from 'react-router-dom';

export default function Navbar() {
  const getStyle = ({ isActive }) => ({
    textDecoration: 'none',
    color: isActive ? '#111827' : '#6b7280',
    fontWeight: isActive ? 700 : 500
  });

  return (
    <nav style={{ borderBottom: '1px solid #e5e7eb', background: '#fff' }}>
      <div style={{ maxWidth: '1100px', margin: '0 auto', padding: '16px 24px', display: 'flex', justifyContent: 'space-between' }}>
        <h2 style={{ margin: 0 }}>BookNest</h2>
        <div style={{ display: 'flex', gap: '18px' }}>
          <NavLink to='/' style={getStyle}>Home</NavLink>
          <NavLink to='/books' style={getStyle}>Books</NavLink>
          <NavLink to='/cart' style={getStyle}>Cart</NavLink>
          <NavLink to='/orders' style={getStyle}>Orders</NavLink>
        </div>
      </div>
    </nav>
  );
}

import React from 'react';

export default function BookCard({ book }) {
  return (
    <div style={{ border: '1px solid #e5e7eb', borderRadius: '14px', padding: '16px', background: '#fff' }}>
      <h3 style={{ marginTop: 0 }}>{book.title}</h3>
      <p style={{ margin: '6px 0', color: '#6b7280' }}>by {book.author}</p>
      <p style={{ margin: '6px 0', color: '#6b7280' }}>Category: {book.category}</p>
      <p style={{ fontWeight: 700 }}>${book.price}</p>
      <button style={{ marginTop: '8px', padding: '10px 14px', background: '#111827', color: '#fff', border: 'none', borderRadius: '10px' }}>
        Add to Cart
      </button>
    </div>
  );
}

import React from 'react';

export default function Home() {
  return (
    <div style={{ maxWidth: '1100px', margin: '0 auto', padding: '32px 24px' }}>
      <div style={{ background: '#f9fafb', borderRadius: '18px', padding: '32px', border: '1px solid #e5e7eb' }}>
        <h1>Discover your next favorite book</h1>
        <p style={{ color: '#4b5563', maxWidth: '680px' }}>
          Search titles, explore categories, and manage your bookstore orders from one clean platform.
        </p>
      </div>
    </div>
  );
}

import React from 'react';
import BookCard from '../components/BookCard';

const books = [
  { id: 1, title: 'Clean Code', author: 'Robert C. Martin', category: 'Programming', price: 28 },
  { id: 2, title: 'Atomic Habits', author: 'James Clear', category: 'Self Help', price: 18 },
  { id: 3, title: 'Deep Work', author: 'Cal Newport', category: 'Productivity', price: 20 }
];

export default function Books() {
  return (
    <div style={{ maxWidth: '1100px', margin: '0 auto', padding: '32px 24px' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', gap: '16px', marginBottom: '20px', flexWrap: 'wrap' }}>
        <input placeholder='Search books...' style={{ padding: '10px 12px', minWidth: '260px', borderRadius: '10px', border: '1px solid #d1d5db' }} />
        <select style={{ padding: '10px 12px', borderRadius: '10px', border: '1px solid #d1d5db' }}>
          <option>All Categories</option>
          <option>Programming</option>
          <option>Self Help</option>
          <option>Productivity</option>
        </select>
      </div>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(240px, 1fr))', gap: '18px' }}>
        {books.map(book => <BookCard key={book.id} book={book} />)}
      </div>
    </div>
  );
}

import React from 'react';

const cartBooks = [
  { id: 1, title: 'Clean Code', quantity: 1, price: 28 },
  { id: 2, title: 'Atomic Habits', quantity: 1, price: 18 }
];

export default function Cart() {
  const total = cartBooks.reduce((sum, book) => sum + book.price * book.quantity, 0);

  return (
    <div style={{ maxWidth: '1100px', margin: '0 auto', padding: '32px 24px' }}>
      <h1>Cart</h1>
      {cartBooks.map(book => (
        <div key={book.id} style={{ display: 'flex', justifyContent: 'space-between', padding: '14px 0', borderBottom: '1px solid #e5e7eb' }}>
          <span>{book.title}</span>
          <span>${book.price}</span>
        </div>
      ))}
      <div style={{ marginTop: '18px', fontWeight: 700 }}>Total: ${total}</div>
    </div>
  );
}

import React from 'react';

const orders = [
  { id: 201, book_count: 2, total: 46, status: 'Shipped' },
  { id: 202, book_count: 1, total: 20, status: 'Processing' }
];

export default function Orders() {
  return (
    <div style={{ maxWidth: '1100px', margin: '0 auto', padding: '32px 24px' }}>
      <h1>Orders</h1>
      <table style={{ width: '100%', borderCollapse: 'collapse', border: '1px solid #e5e7eb', borderRadius: '12px', overflow: 'hidden' }}>
        <thead style={{ background: '#f9fafb' }}>
          <tr>
            <th style={{ padding: '12px', textAlign: 'left' }}>Order ID</th>
            <th style={{ padding: '12px', textAlign: 'left' }}>Books</th>
            <th style={{ padding: '12px', textAlign: 'left' }}>Total</th>
            <th style={{ padding: '12px', textAlign: 'left' }}>Status</th>
          </tr>
        </thead>
        <tbody>
          {orders.map(order => (
            <tr key={order.id}>
              <td style={{ padding: '12px', borderTop: '1px solid #e5e7eb' }}>#{order.id}</td>
              <td style={{ padding: '12px', borderTop: '1px solid #e5e7eb' }}>{order.book_count}</td>
              <td style={{ padding: '12px', borderTop: '1px solid #e5e7eb' }}>${order.total}</td>
              <td style={{ padding: '12px', borderTop: '1px solid #e5e7eb' }}>{order.status}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

from flask import Flask, jsonify

app = Flask(__name__)

@app.route('/api/books')
def get_books():
    return jsonify({
        'books': [
            {'id': 1, 'title': 'Clean Code', 'author': 'Robert C. Martin', 'category': 'Programming', 'price': 28},
            {'id': 2, 'title': 'Atomic Habits', 'author': 'James Clear', 'category': 'Self Help', 'price': 18},
            {'id': 3, 'title': 'Deep Work', 'author': 'Cal Newport', 'category': 'Productivity', 'price': 20}
        ]
    })

@app.route('/api/orders')
def get_orders():
    return jsonify({
        'orders': [
            {'id': 201, 'book_count': 2, 'total_amount': 46, 'status': 'Shipped'},
            {'id': 202, 'book_count': 1, 'total_amount': 20, 'status': 'Processing'}
        ]
    })

if __name__ == '__main__':
    app.run(debug=True)
